const agreements = $input.first().json.entries ?? [];

if (!Array.isArray(agreements)) {
  throw new Error('Anchor agreements response did not include entries[]');
}

return agreements.map((agreement) => ({
  json: {
    relationshipId: agreement.id,
    agreementName: agreement.name ?? null,
    clientBusinessName: agreement.client?.business?.name ?? null,
  },
}));

const invoiceItems = [];
const overLimitRelationships = [];

for (const item of $input.all()) {
  const root = item.json;
  const invoices = Array.isArray(root.entries) ? root.entries : [];
  if ((root.totalCount ?? 0) > (root.limit ?? 100)) {
    overLimitRelationships.push({ totalCount: root.totalCount, limit: root.limit });
  }

  for (const invoice of invoices) {
    invoiceItems.push({
      json: {
        invoiceId: invoice.id,
        listInvoice: invoice,
        overLimitRelationships,
      },
    });
  }
}

return invoiceItems;

const lastSeenAt = new Date().toISOString();

function parseMoney(value) {
  if (value === undefined || value === null || value === '') return null;
  if (typeof value === 'number') return value;
  const cleaned = String(value).replace(/[$,]/g, '').trim();
  if (!cleaned) return null;
  const parsed = Number(cleaned);
  return Number.isFinite(parsed) ? parsed : null;
}

function parseNumber(value) {
  if (value === undefined || value === null || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function invoiceNote(invoice) {
  return invoice.note ?? invoice.notes ?? invoice.memo ?? invoice.description ?? invoice.message ?? null;
}

function serviceNameForLineItem(lineItem) {
  return lineItem.name
    ?? lineItem.serviceName
    ?? lineItem.service?.name
    ?? lineItem.origin?.serviceBundle?.name
    ?? lineItem.integrations?.quickbooks?.item?.name
    ?? null;
}

function flattenLineItems(invoice, lineItems, parentLineItemId = null) {
  const rows = [];

  for (const lineItem of lineItems ?? []) {
    const children = [
      ...(Array.isArray(lineItem.groupedLineItems) ? lineItem.groupedLineItems : []),
      ...(Array.isArray(lineItem.subItems) ? lineItem.subItems : []),
    ];

    rows.push({
      anchor_line_item_id: lineItem.id,
      anchor_invoice_id: invoice.id,
      anchor_relationship_id: invoice.agreement?.id ?? null,
      parent_line_item_id: parentLineItemId,
      service_id: lineItem.serviceId ?? lineItem.origin?.serviceBundle?.bundleItemId ?? null,
      service_template_id: lineItem.serviceTemplateId ?? lineItem.origin?.serviceBundle?.serviceTemplateId ?? null,
      service_name: serviceNameForLineItem(lineItem),
      name: lineItem.name ?? null,
      amount: parseMoney(lineItem.amount),
      rate: parseMoney(lineItem.rate),
      quantity: parseNumber(lineItem.quantity),
      unit_name: lineItem.unitName ?? null,
      qbo_product_id: lineItem.integrations?.quickbooks?.item?.id ?? null,
      qbo_product_name: lineItem.integrations?.quickbooks?.item?.name ?? null,
      is_bundle_parent: children.length > 0,
      raw: lineItem,
      last_seen_at: lastSeenAt,
    });

    rows.push(...flattenLineItems(invoice, children, lineItem.id));
  }

  return rows;
}

const invoices = $input.all().map((item) => item.json);
const invoiceRows = invoices.map((invoice) => ({
  anchor_invoice_id: invoice.id,
  anchor_relationship_id: invoice.agreement?.id ?? null,
  invoice_number: invoice.invoiceNumber ?? null,
  issue_date: invoice.issueDate ?? null,
  due_date: invoice.dueDate ?? null,
  total_amount: parseMoney(invoice.totalAmount),
  amount_paid: parseMoney(invoice.amountPaid),
  amount_due: parseMoney(invoice.amountDue),
  display_status: invoice.status?.displayStatus ?? invoice.status?.type ?? null,
  qbo_status: invoice.integrations?.quickbooks?.status ?? null,
  invoice_note: invoiceNote(invoice),
  raw: invoice,
  last_seen_at: lastSeenAt,
}));

const lineRows = invoices.flatMap((invoice) => flattenLineItems(invoice, invoice.lineItems));

return [
  {
    json: {
      invoiceCount: invoiceRows.length,
      lineItemCount: lineRows.length,
      invoiceRows,
      lineRows,
      sampleInvoices: invoiceRows.slice(0, 5).map((row) => ({
        anchor_invoice_id: row.anchor_invoice_id,
        invoice_number: row.invoice_number,
        anchor_relationship_id: row.anchor_relationship_id,
        total_amount: row.total_amount,
        display_status: row.display_status,
        invoice_note: row.invoice_note,
      })),
      sampleLineItems: lineRows.slice(0, 5).map((row) => ({
        anchor_line_item_id: row.anchor_line_item_id,
        anchor_invoice_id: row.anchor_invoice_id,
        service_name: row.service_name,
        name: row.name,
        amount: row.amount,
        qbo_product_name: row.qbo_product_name,
      })),
    },
  },
];

const rows = $input.all().map((item) => item.json);
return [
  {
    json: {
      status: 'ok',
      upsertedInvoiceCount: rows.length,
      sample: rows.slice(0, 5).map((row) => ({
        anchor_invoice_id: row.anchor_invoice_id,
        invoice_number: row.invoice_number,
        total_amount: row.total_amount,
        display_status: row.display_status,
      })),
    },
  },
];

const rows = $input.all().map((item) => item.json);
return [
  {
    json: {
      status: 'ok',
      upsertedLineItemCount: rows.length,
      sample: rows.slice(0, 5).map((row) => ({
        anchor_line_item_id: row.anchor_line_item_id,
        anchor_invoice_id: row.anchor_invoice_id,
        name: row.name,
        amount: row.amount,
        qbo_product_name: row.qbo_product_name,
      })),
    },
  },
];
